    "ask": ["Bash(rm *)"],
    "defaultMode": "dontAsk",
    "autoMode": {
      "environment": [
        "Project: freddie-ai — music prompt engineering toolkit and Obsidian vault manager",
        "Runtime: bun, Node.js on Windows 11",
        "Trusted tools: bun, git, gh, npm",
        "APIs: MiniMax, Gemini, Grok (keys in .env)"
      ],
      "allow": [
        "Writing to vault/ is safe — personal Obsidian vault synced via iCloud",
        "Writing to out/ is safe — gitignored scratch folder",
        "Web fetch and search are allowed for research"
      ],
      "soft_deny": [
        "Never delete files under vault/ without asking",
        "Never push to remote without explicit confirmation"
      ]
    }
  },
  "hooks": {
    "SessionStart": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "bun \"$CLAUDE_PROJECT_DIR/.claude/hooks/tool-call-counter.ts\" --reset"
          },
          {
            "type": "command",
            "command": "bun \"$CLAUDE_PROJECT_DIR/src/tools/brain.ts\" --check"
          }
        ]
      }
    ],
    "PostToolUse": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "bun \"$CLAUDE_PROJECT_DIR/.claude/hooks/tool-call-counter.ts\""
          },
          {
            "type": "command",
            "command": "bun \"$CLAUDE_PROJECT_DIR/.claude/hooks/capture-raw.ts\" --post-tool"
          }
        ]
      }
    ],
    "Stop": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "bun \"$CLAUDE_PROJECT_DIR/.claude/hooks/tool-call-counter.ts\" --check"
          },
          {
            "type": "command",
            "command": "bun \"$CLAUDE_PROJECT_DIR/.claude/hooks/capture-raw.ts\" --stop"
          },
          {
            "type": "command",
            "command": "bun \"$CLAUDE_PROJECT_DIR/src/tools/brain.ts\" --check"
          }
        ]
      }
    ],
    "PreCompact": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "bun \"$CLAUDE_PROJECT_DIR/.claude/hooks/pre-compact-save.ts\""
          },
          {
            "type": "command",
            "command": "bun \"$CLAUDE_PROJECT_DIR/.claude/hooks/capture-raw.ts\" --pre-compact"
          }
        ]
      }
    ]
  }
}

