#!/usr/bin/env bun
/**
 * init.ts — Session briefing for Freddie
 *
 * SessionStart hook: loads soul, scans knowledge + daily note + inbox counts,
 * outputs a Pennyworth-style briefing to stdout (injected into session context).
 *
 * Design: fast (<500ms), read-only, no file mutations.
 */

import { readFileSync, readdirSync, existsSync } from "fs";
import { join, basename } from "path";
import { fromRoot } from "../../src/libs/paths.js";
import { today, now } from "../../src/libs/dates.js";

// ── Paths ─────────────────────────────────────────────────────────────────

const SOUL_PATH = fromRoot(".claude", "souls", "freddie.md");
const MEMORY_DIR = fromRoot("vault", "studio", "memory");
const DAILY_DIR = fromRoot("vault", "notes", "daily");
const AUTO_MEMORY_DIR = join(
  process.env.HOME || process.env.USERPROFILE || "",
  ".claude-personal",
  "projects",
  "d--PROJECTS-freddie-ai",
  "memory"
);

// ── Greetings ─────────────────────────────────────────────────────────────

const GREETINGS = {
  morning: [
    "Good morning, Odie. The studio is warmed up and ready.",
    "Morning, sir. Fresh day, fresh context. Shall we begin?",
    "Good morning. I've laid out the briefing — coffee's on you.",
    "Rise and shine, Odie. The agents are standing by.",
  ],
  afternoon: [
    "Good afternoon, Odie. What are we building today?",
    "Afternoon, sir. The board is set. Your move.",
    "Good afternoon. I've reviewed the state of things — here's where we are.",
    "Afternoon, Odie. Let's pick up where we left off.",
  ],
  evening: [
    "Good evening, Odie. Ready for your shift?",
    "Evening, sir. The night shift has its advantages — fewer interruptions.",
    "Good evening. I've prepared your briefing. The vault is quiet.",
    "Evening, Odie. Let's make the most of the quiet hours.",
  ],
};

function getGreeting(hour: number): string {
  let pool: string[];
  if (hour >= 5 && hour < 12) pool = GREETINGS.morning;
  else if (hour >= 12 && hour < 18) pool = GREETINGS.afternoon;
  else pool = GREETINGS.evening;
  return pool[Math.floor(Math.random() * pool.length)];
}

// ── Soul loader ───────────────────────────────────────────────────────────

function loadSoulSummary(): string | null {
  if (!existsSync(SOUL_PATH)) return null;
  const content = readFileSync(SOUL_PATH, "utf-8");
  // Extract first line (title) for identity confirmation
  const title = content.split("\n").find((l) => l.startsWith("# "));
  return title?.replace(/^#\s*/, "") || null;
}

// ── Knowledge scanner ─────────────────────────────────────────────────────

interface AgentMemoryStatus {
  agent: string;
  inboxCount: number;
  knowledgeCount: number;
}

function scanAgentMemory(): AgentMemoryStatus[] {
  if (!existsSync(MEMORY_DIR)) return [];
  const agents = readdirSync(MEMORY_DIR, { withFileTypes: true })
    .filter((d) => d.isDirectory())
    .map((d) => d.name);

  return agents
    .map((agent) => {
      const inboxDir = join(MEMORY_DIR, agent, "inbox");
      const knowledgeDir = join(MEMORY_DIR, agent, "knowledge");
      const inboxCount = existsSync(inboxDir)
        ? readdirSync(inboxDir).filter((f) => f.endsWith(".md")).length
        : 0;
      const knowledgeCount = existsSync(knowledgeDir)
        ? readdirSync(knowledgeDir).filter((f) => f.endsWith(".md")).length
        : 0;
      return { agent, inboxCount, knowledgeCount };
    })
    .filter((a) => a.inboxCount > 0 || a.knowledgeCount > 0);
}

// ── Daily note parser ─────────────────────────────────────────────────────

interface TaskInfo {
  text: string;
  done: boolean;
}

function parseDailyTasks(dateStr: string): TaskInfo[] {
  const notePath = join(DAILY_DIR, `${dateStr}.md`);
  if (!existsSync(notePath)) return [];

  const content = readFileSync(notePath, "utf-8");
  const lines = content.split("\n");

  // Find ## Tasks section, collect top-level tasks only (not subtasks)
  let inTasks = false;
  const tasks: TaskInfo[] = [];

  for (const line of lines) {
    if (line.startsWith("## Tasks")) {
      inTasks = true;
      continue;
    }
    if (inTasks && line.startsWith("## ")) break;
    if (!inTasks) continue;

    // Top-level tasks only (- [ ] or - [x], not indented)
    const taskMatch = line.match(/^- \[([ x])\] (.+)/);
    if (taskMatch) {
      // Strip wikilink trail (← [[...]])
      let text = taskMatch[2].replace(/\s*←\s*\[\[.*$/s, "").trim();
      // Truncate long task text
      if (text.length > 80) text = text.slice(0, 77) + "...";
      tasks.push({ text, done: taskMatch[1] === "x" });
    }
  }

  return tasks;
}

// ── Last session finder ───────────────────────────────────────────────────

interface SessionInfo {
  date: string;
  summary: string;
}

function findLastSession(): SessionInfo | null {
  if (!existsSync(AUTO_MEMORY_DIR)) return null;

  const sessionFiles = readdirSync(AUTO_MEMORY_DIR)
    .filter((f) => f.startsWith("project_session_") && f.endsWith(".md"))
    .sort()
    .reverse();

  if (sessionFiles.length === 0) return null;

  const latest = sessionFiles[0];
  const content = readFileSync(join(AUTO_MEMORY_DIR, latest), "utf-8");

  // Extract date from filename: project_session_YYYYMMDD*.md
  const dateMatch = latest.match(/project_session_(\d{4})(\d{2})(\d{2})/);
  const date = dateMatch ? `${dateMatch[1]}-${dateMatch[2]}-${dateMatch[3]}` : "unknown";

  // Extract description from frontmatter or first content line
  const descMatch = content.match(/^description:\s*(.+)$/m);
  const summary = descMatch?.[1] || content.split("\n").find((l) => l.length > 10 && !l.startsWith("---") && !l.startsWith("name:") && !l.startsWith("type:"))?.trim() || "No summary available";

  return { date, summary: summary.length > 120 ? summary.slice(0, 117) + "..." : summary };
}

// ── Suggestions ───────────────────────────────────────────────────────────

function buildSuggestions(
  agentStatuses: AgentMemoryStatus[],
  tasks: TaskInfo[],
  lastSession: SessionInfo | null
): string[] {
  const suggestions: string[] = [];

  // Inbox consolidation alerts
  const needsConsolidation = agentStatuses.filter((a) => a.inboxCount >= 3);
  for (const a of needsConsolidation) {
    suggestions.push(`${capitalize(a.agent)} has ${a.inboxCount} inbox items — consolidation ready`);
  }

  // Inbox items worth noting (< 3, just awareness)
  const hasInbox = agentStatuses.filter((a) => a.inboxCount > 0 && a.inboxCount < 3);
  if (hasInbox.length > 0) {
    const names = hasInbox.map((a) => `${capitalize(a.agent)} (${a.inboxCount})`).join(", ");
    suggestions.push(`Inbox items: ${names}`);
  }

  // Carryover tasks (tasks that have been around, marked by ← links)
  const openTasks = tasks.filter((t) => !t.done);
  if (openTasks.length > 5) {
    suggestions.push(`${openTasks.length} open tasks — consider triaging or deferring some`);
  }

  return suggestions;
}

function capitalize(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

// ── Main ──────────────────────────────────────────────────────────────────

function main() {
  const { date, time } = now();
  const hour = parseInt(time.slice(0, 2), 10);
  const greeting = getGreeting(hour);
  const soul = loadSoulSummary();
  const agentStatuses = scanAgentMemory();
  const tasks = parseDailyTasks(date);
  const lastSession = findLastSession();
  const suggestions = buildSuggestions(agentStatuses, tasks, lastSession);

  // ── Build output ──────────────────────────────────────────────────────

  const lines: string[] = [];

  // Identity + greeting
  if (soul) lines.push(`[${soul}]`);
  lines.push("");
  lines.push(greeting);
  lines.push("");
  lines.push("━━ Briefing ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
  lines.push("");

  // Tasks
  if (tasks.length > 0) {
    lines.push("Tasks:");
    const openTasks = tasks.filter((t) => !t.done);
    const doneTasks = tasks.filter((t) => t.done);

    for (const t of openTasks.slice(0, 8)) {
      lines.push(`  [ ] ${t.text}`);
    }
    if (openTasks.length > 8) {
      lines.push(`  ... and ${openTasks.length - 8} more`);
    }
    if (doneTasks.length > 0) {
      lines.push(`  (${doneTasks.length} completed today)`);
    }
    lines.push("");
  } else {
    lines.push("Tasks: No daily note for today yet.");
    lines.push("");
  }

  // Last session
  if (lastSession) {
    lines.push(`Last session (${lastSession.date}):`);
    lines.push(`  ${lastSession.summary}`);
    lines.push("");
  }

  // Suggestions
  if (suggestions.length > 0) {
    lines.push("Suggested:");
    for (const s of suggestions) {
      lines.push(`  > ${s}`);
    }
    lines.push("");
  }

  // Agent knowledge summary (compact)
  const withKnowledge = agentStatuses.filter((a) => a.knowledgeCount > 0);
  if (withKnowledge.length > 0) {
    const summary = withKnowledge
      .map((a) => `${capitalize(a.agent)}(${a.knowledgeCount})`)
      .join(" ");
    lines.push(`Knowledge loaded: ${summary}`);
    lines.push("");
  }

  lines.push("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");

  const output = lines.join("\n");
  process.stdout.write(output);
}

try {
  main();
} catch (err) {
  // Never block session start — fail silently
  process.stderr.write(`[init] Error: ${err instanceof Error ? err.message : String(err)}\n`);
}

process.exit(0);

