    descMatch?.[1] ||
    content
      .split("\n")
      .find(
        (l) =>
          l.length > 10 &&
          !l.startsWith("---") &&
          !l.startsWith("name:") &&
          !l.startsWith("type:")
      )
      ?.trim() ||
    "No summary available";

  return { date, summary: summary.length > 120 ? summary.slice(0, 117) + "..." : summary };
}

